  1→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  2→import { z } from "zod";
  3→import { createWorkflow } from "@/be/db";
  4→import { createToolRegistrar } from "@/tools/utils";
  5→import {
  6→  CooldownConfigSchema,
  7→  InputValueSchema,
  8→  TriggerConfigSchema,
  9→  WorkflowDefinitionSchema,
 10→} from "@/types";
 11→import { validateDefinition } from "@/workflows/definition";
 12→
 13→export const registerCreateWorkflowTool = (server: McpServer) => {
 14→  createToolRegistrar(server)(
 15→    "create-workflow",
 16→    {
 17→      title: "Create Workflow",
 18→      annotations: { destructiveHint: false },
 19→      description:
 20→        "Create a new automation workflow with a nodes-with-next definition, optional triggers, cooldown, and input.",
 21→      inputSchema: z.object({
 22→        name: z.string().describe("Unique name for the workflow"),
 23→        description: z.string().optional().describe("Description of what this workflow does"),
 24→        definition: WorkflowDefinitionSchema.describe(
 25→          "The workflow definition with nodes (each node has id, type, config, and optional next/retry/validation)",
 26→        ),
 27→        triggers: z
 28→          .array(TriggerConfigSchema)
 29→          .optional()
 30→          .describe("Optional trigger configurations (webhook, schedule)"),
 31→        cooldown: CooldownConfigSchema.optional().describe(
 32→          "Optional cooldown configuration to prevent re-triggering too frequently",
 33→        ),
 34→        input: z
 35→          .record(z.string(), InputValueSchema)
 36→          .optional()
 37→          .describe(
 38→            "Optional input values resolved at execution time (env vars like VAR_NAME, secrets secret.NAME, or literals)",
 39→          ),
 40→      }),
 41→      outputSchema: z.object({
 42→        yourAgentId: z.string().optional(),
 43→        success: z.boolean(),
 44→        message: z.string(),
 45→        workflow: z.unknown().optional(),
 46→      }),
 47→    },
 48→    async ({ name, description, definition, triggers, cooldown, input }, requestInfo) => {
 49→      if (!requestInfo.agentId) {
 50→        return {
 51→          content: [{ type: "text" as const, text: "Agent ID required." }],
 52→          structuredContent: { success: false, message: "Agent ID required." },
 53→        };
 54→      }
 55→      try {
 56→        // Validate definition structure
 57→        const validation = validateDefinition(definition);
 58→        if (!validation.valid) {
 59→          return {
 60→            content: [
 61→              {
 62→                type: "text" as const,
 63→                text: `Invalid definition: ${validation.errors.join("; ")}`,
 64→              },
 65→            ],
 66→            structuredContent: {
 67→              success: false,
 68→              message: `Invalid definition: ${validation.errors.join("; ")}`,
 69→            },
 70→          };
 71→        }
 72→
 73→        const workflow = createWorkflow({
 74→          name,
 75→          description,
 76→          definition,
 77→          triggers,
 78→          cooldown,
 79→          input,
 80→          createdByAgentId: requestInfo.agentId,
 81→        });
 82→        return {
 83→          content: [
 84→            {
 85→              type: "text" as const,
 86→              text: `Created workflow "${workflow.name}" (${workflow.id}).`,
 87→            },
 88→          ],
 89→          structuredContent: {
 90→            yourAgentId: requestInfo.agentId,
 91→            success: true,
 92→            message: `Created workflow "${workflow.name}".`,
 93→            workflow,
 94→          },
 95→        };
 96→      } catch (err) {
 97→        return {
 98→          content: [{ type: "text" as const, text: `Failed: ${err}` }],
 99→          structuredContent: { success: false, message: String(err) },
100→        };
101→      }
102→    },
103→  );
104→};
