 1→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 2→import { z } from "zod";
 3→import { getWorkflow, getWorkflowRun } from "@/be/db";
 4→import { createToolRegistrar } from "@/tools/utils";
 5→import { getExecutorRegistry, startWorkflowExecution } from "@/workflows";
 6→
 7→export const registerTriggerWorkflowTool = (server: McpServer) => {
 8→  createToolRegistrar(server)(
 9→    "trigger-workflow",
10→    {
11→      title: "Trigger Workflow",
12→      annotations: { destructiveHint: false },
13→      description:
14→        "Manually trigger a workflow execution, optionally passing trigger data as context. Respects cooldown configuration.",
15→      inputSchema: z.object({
16→        id: z.string().uuid().describe("Workflow ID to trigger"),
17→        triggerData: z
18→          .record(z.string(), z.unknown())
19→          .optional()
20→          .describe("Optional data to pass as trigger context to the workflow"),
21→      }),
22→      outputSchema: z.object({
23→        success: z.boolean(),
24→        message: z.string(),
25→        runId: z.string().optional(),
26→        skipped: z.boolean().optional(),
27→      }),
28→    },
29→    async ({ id, triggerData }) => {
30→      try {
31→        const workflow = getWorkflow(id);
32→        if (!workflow) {
33→          return {
34→            content: [{ type: "text" as const, text: `Workflow not found: ${id}` }],
35→            structuredContent: { success: false, message: `Workflow not found: ${id}` },
36→          };
37→        }
38→        if (!workflow.enabled) {
39→          return {
40→            content: [{ type: "text" as const, text: `Workflow "${workflow.name}" is disabled.` }],
41→            structuredContent: {
42→              success: false,
43→              message: `Workflow "${workflow.name}" is disabled.`,
44→            },
45→          };
46→        }
47→        const runId = await startWorkflowExecution(
48→          workflow,
49→          triggerData ?? {},
50→          getExecutorRegistry(),
51→        );
52→
53→        // Check if the run was skipped due to cooldown
54→        const run = getWorkflowRun(runId);
55→        const skipped = run?.status === "skipped";
56→
57→        if (skipped) {
58→          return {
59→            content: [
60→              {
61→                type: "text" as const,
62→                text: `Workflow "${workflow.name}" skipped (cooldown active) — run ID: ${runId}.`,
63→              },
64→            ],
65→            structuredContent: {
66→              success: true,
67→              message: `Workflow "${workflow.name}" skipped (cooldown).`,
68→              runId,
69→              skipped: true,
70→            },
71→          };
72→        }
73→
74→        return {
75→          content: [
76→            {
77→              type: "text" as const,
78→              text: `Triggered workflow "${workflow.name}" — run ID: ${runId}.`,
79→            },
80→          ],
81→          structuredContent: {
82→            success: true,
83→            message: `Triggered workflow "${workflow.name}".`,
84→            runId,
85→            skipped: false,
86→          },
87→        };
88→      } catch (err) {
89→        return {
90→          content: [{ type: "text" as const, text: `Failed: ${err}` }],
91→          structuredContent: { success: false, message: String(err) },
92→        };
93→      }
94→    },
95→  );
96→};
