 1→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
 2→import { z } from "zod";
 3→import { getWorkflowRun, getWorkflowRunStepsByRunId } from "@/be/db";
 4→import { createToolRegistrar } from "@/tools/utils";
 5→
 6→export const registerGetWorkflowRunTool = (server: McpServer) => {
 7→  createToolRegistrar(server)(
 8→    "get-workflow-run",
 9→    {
10→      title: "Get Workflow Run",
11→      annotations: { destructiveHint: false },
12→      description: "Get details of a workflow run by ID, including all steps and their statuses.",
13→      inputSchema: z.object({
14→        id: z.string().uuid().describe("Workflow run ID"),
15→      }),
16→      outputSchema: z.object({
17→        success: z.boolean(),
18→        message: z.string(),
19→        run: z.unknown().optional(),
20→        steps: z.array(z.unknown()),
21→      }),
22→    },
23→    async ({ id }) => {
24→      try {
25→        const run = getWorkflowRun(id);
26→        if (!run) {
27→          return {
28→            content: [{ type: "text" as const, text: `Workflow run not found: ${id}` }],
29→            structuredContent: {
30→              success: false,
31→              message: `Workflow run not found: ${id}`,
32→              steps: [],
33→            },
34→          };
35→        }
36→        const steps = getWorkflowRunStepsByRunId(id);
37→        return {
38→          content: [
39→            {
40→              type: "text" as const,
41→              text: `Run ${id} — status: ${run.status}, steps: ${steps.length}.`,
42→            },
43→          ],
44→          structuredContent: {
45→            success: true,
46→            message: `Run ${id} status: ${run.status}.`,
47→            run,
48→            steps,
49→          },
50→        };
51→      } catch (err) {
52→        return {
53→          content: [{ type: "text" as const, text: `Failed: ${err}` }],
54→          structuredContent: { success: false, message: String(err), steps: [] },
55→        };
56→      }
57→    },
58→  );
59→};
