  1→import type { IncomingMessage, ServerResponse } from "node:http";
  2→import { z } from "zod";
  3→import {
  4→  createWorkflow,
  5→  deleteWorkflow,
  6→  getWorkflow,
  7→  getWorkflowRun,
  8→  getWorkflowRunStepsByRunId,
  9→  getWorkflowVersion,
 10→  getWorkflowVersions,
 11→  listWorkflowRuns,
 12→  listWorkflows,
 13→  updateWorkflow,
 14→} from "../be/db";
 15→import {
 16→  CooldownConfigSchema,
 17→  InputValueSchema,
 18→  TriggerConfigSchema,
 19→  WorkflowDefinitionSchema,
 20→  WorkflowRunStatusSchema,
 21→} from "../types";
 22→import { getExecutorRegistry, startWorkflowExecution } from "../workflows";
 23→import { generateEdges, validateDefinition } from "../workflows/definition";
 24→import { TriggerSchemaError } from "../workflows/engine";
 25→import { retryFailedRun } from "../workflows/resume";
 26→import { handleWebhookTrigger, WebhookError } from "../workflows/triggers";
 27→import { snapshotWorkflow } from "../workflows/version";
 28→import { route } from "./route-def";
 29→import { json, jsonError, parseBody } from "./utils";
 30→
 31→// ─── Route Definitions ───────────────────────────────────────────────────────
 32→
 33→const listWorkflowsRoute = route({
 34→  method: "get",
 35→  path: "/api/workflows",
 36→  pattern: ["api", "workflows"],
 37→  summary: "List all workflows",
 38→  tags: ["Workflows"],
 39→  responses: {
 40→    200: { description: "Workflow list" },
 41→  },
 42→});
 43→
 44→const createWorkflowRoute = route({
 45→  method: "post",
 46→  path: "/api/workflows",
 47→  pattern: ["api", "workflows"],
 48→  summary: "Create a new workflow",
 49→  tags: ["Workflows"],
 50→  body: z.object({
 51→    name: z.string().min(1),
 52→    description: z.string().optional(),
 53→    definition: WorkflowDefinitionSchema,
 54→    triggers: z.array(TriggerConfigSchema).optional(),
 55→    cooldown: CooldownConfigSchema.optional(),
 56→    input: z.record(z.string(), InputValueSchema).optional(),
 57→    triggerSchema: z.record(z.string(), z.unknown()).optional(),
 58→  }),
 59→  responses: {
 60→    201: { description: "Workflow created" },
 61→    400: { description: "Invalid definition" },
 62→  },
 63→});
 64→
 65→const getWorkflowRoute = route({
 66→  method: "get",
 67→  path: "/api/workflows/{id}",
 68→  pattern: ["api", "workflows", null],
 69→  summary: "Get a workflow by ID",
 70→  tags: ["Workflows"],
 71→  params: z.object({ id: z.string() }),
 72→  responses: {
 73→    200: { description: "Workflow details with auto-generated edges" },
 74→    404: { description: "Workflow not found" },
 75→  },
 76→});
 77→
 78→const updateWorkflowRoute = route({
 79→  method: "put",
 80→  path: "/api/workflows/{id}",
 81→  pattern: ["api", "workflows", null],
 82→  summary: "Update a workflow",
 83→  tags: ["Workflows"],
 84→  params: z.object({ id: z.string() }),
 85→  body: z.object({
 86→    name: z.string().optional(),
 87→    description: z.string().optional(),
 88→    definition: WorkflowDefinitionSchema.optional(),
 89→    triggers: z.array(TriggerConfigSchema).optional(),
 90→    cooldown: CooldownConfigSchema.optional().nullable(),
 91→    input: z.record(z.string(), InputValueSchema).optional().nullable(),
 92→    triggerSchema: z.record(z.string(), z.unknown()).optional().nullable(),
 93→    enabled: z.boolean().optional(),
 94→  }),
 95→  responses: {
 96→    200: { description: "Workflow updated (version snapshot created)" },
 97→    400: { description: "Invalid definition" },
 98→    404: { description: "Workflow not found" },
 99→  },
100→});
101→
102→const deleteWorkflowRoute = route({
103→  method: "delete",
104→  path: "/api/workflows/{id}",
105→  pattern: ["api", "workflows", null],
106→  summary: "Delete a workflow",
107→  tags: ["Workflows"],
108→  params: z.object({ id: z.string() }),
109→  responses: {
110→    204: { description: "Workflow deleted" },
111→    404: { description: "Workflow not found" },
112→  },
113→});
114→
115→const triggerWorkflowRoute = route({
116→  method: "post",
117→  path: "/api/workflows/{id}/trigger",
118→  pattern: ["api", "workflows", null, "trigger"],
119→  summary: "Trigger a workflow execution",
120→  tags: ["Workflows"],
121→  params: z.object({ id: z.string() }),
122→  responses: {
123→    201: { description: "Workflow run started (or skipped if cooldown active)" },
124→    400: { description: "Workflow is disabled" },
125→    401: { description: "Unauthorized" },
126→    404: { description: "Workflow not found" },
127→  },
128→});
129→
130→const listWorkflowRunsRoute = route({
131→  method: "get",
132→  path: "/api/workflows/{id}/runs",
133→  pattern: ["api", "workflows", null, "runs"],
134→  summary: "List runs for a workflow",
135→  tags: ["Workflows"],
136→  params: z.object({ id: z.string() }),
137→  query: z.object({
138→    status: WorkflowRunStatusSchema.optional(),
139→  }),
140→  responses: {
141→    200: { description: "Workflow run list" },
142→  },
143→});
144→
145→const getWorkflowRunRoute = route({
146→  method: "get",
147→  path: "/api/workflow-runs/{id}",
148→  pattern: ["api", "workflow-runs", null],
149→  summary: "Get a workflow run with steps (includes retry columns)",
150→  tags: ["Workflows"],
151→  params: z.object({ id: z.string() }),
152→  responses: {
153→    200: { description: "Workflow run details with steps including retry info" },
154→    404: { description: "Run not found" },
155→  },
156→});
157→
158→const retryWorkflowRunRoute = route({
159→  method: "post",
160→  path: "/api/workflow-runs/{id}/retry",
161→  pattern: ["api", "workflow-runs", null, "retry"],
162→  summary: "Retry a failed workflow run",
163→  tags: ["Workflows"],
164→  params: z.object({ id: z.string() }),
165→  responses: {
166→    200: { description: "Retry started" },
167→    400: { description: "Cannot retry" },
168→  },
169→});
170→
171→const listExecutorTypesRoute = route({
172→  method: "get",
173→  path: "/api/executor-types",
174→  pattern: ["api", "executor-types"],
175→  summary: "List all executor types with their config and output schemas",
176→  tags: ["Workflows"],
177→  responses: {
178→    200: { description: "List of executor types with schemas" },
179→  },
180→});
181→
182→const getExecutorTypeRoute = route({
183→  method: "get",
184→  path: "/api/executor-types/{type}",
185→  pattern: ["api", "executor-types", null],
186→  summary: "Get a specific executor type with its schemas",
187→  tags: ["Workflows"],
188→  params: z.object({ type: z.string() }),
189→  responses: {
190→    200: { description: "Executor type details" },
191→    404: { description: "Executor type not found" },
192→  },
193→});
194→
195→const webhookTriggerRoute = route({
196→  method: "post",
197→  path: "/api/webhooks/{workflowId}",
198→  pattern: ["api", "webhooks", null],
199→  summary: "Trigger workflow via webhook",
200→  tags: ["Webhooks"],
201→  params: z.object({ workflowId: z.string() }),
202→  auth: { apiKey: false },
203→  responses: {
204→    201: { description: "Webhook processed" },
205→    401: { description: "Invalid signature" },
206→    404: { description: "Workflow not found" },
207→  },
208→});
209→
210→// ─── Version History Route Definitions ────────────────────────────────────────
211→
212→const listWorkflowVersionsRoute = route({
213→  method: "get",
214→  path: "/api/workflows/{id}/versions",
215→  pattern: ["api", "workflows", null, "versions"],
216→  summary: "List version history for a workflow",
217→  tags: ["Workflows"],
218→  params: z.object({ id: z.string() }),
219→  responses: {
220→    200: { description: "Version list (newest first)" },
221→    404: { description: "Workflow not found" },
222→  },
223→});
224→
225→const getWorkflowVersionRoute = route({
226→  method: "get",
227→  path: "/api/workflows/{id}/versions/{version}",
228→  pattern: ["api", "workflows", null, "versions", null],
229→  summary: "Get a specific version snapshot of a workflow",
230→  tags: ["Workflows"],
231→  params: z.object({ id: z.string(), version: z.coerce.number().int().min(1) }),
232→  responses: {
233→    200: { description: "Version snapshot" },
234→    404: { description: "Version not found" },
235→  },
236→});
237→
238→// ─── Handler ─────────────────────────────────────────────────────────────────
239→
240→export async function handleWorkflows(
241→  req: IncomingMessage,
242→  res: ServerResponse,
243→  pathSegments: string[],
244→  queryParams: URLSearchParams,
245→  myAgentId: string | undefined,
246→): Promise<boolean> {
247→  // Executor type schemas
248→  if (listExecutorTypesRoute.match(req.method, pathSegments)) {
249→    const registry = getExecutorRegistry();
250→    json(res, { executorTypes: registry.describeAll() });
251→    return true;
252→  }
253→
254→  if (getExecutorTypeRoute.match(req.method, pathSegments)) {
255→    const parsed = await getExecutorTypeRoute.parse(req, res, pathSegments, queryParams);
256→    if (!parsed) return true;
257→    const registry = getExecutorRegistry();
258→    if (!registry.has(parsed.params.type)) {
259→      res.writeHead(404);
260→      res.end();
261→      return true;
262→    }
263→    json(res, registry.describe(parsed.params.type));
264→    return true;
265→  }
266→
267→  // Webhook trigger — needs raw body for HMAC verification, no API key auth
268→  if (webhookTriggerRoute.match(req.method, pathSegments)) {
269→    const workflowId = pathSegments[2]!;
270→
271→    // Read raw body for HMAC verification
272→    const chunks: Buffer[] = [];
273→    for await (const chunk of req) {
274→      chunks.push(chunk as Buffer);
275→    }
276→    const rawBody = Buffer.concat(chunks).toString();
277→
278→    // Validate JSON before processing (but pass raw string for HMAC)
279→    try {
280→      if (rawBody) JSON.parse(rawBody);
281→    } catch {
282→      jsonError(res, "Invalid JSON body", 400);
283→      return true;
284→    }
285→
286→    const signature =
287→      (req.headers["x-hub-signature-256"] as string | undefined) ??
288→      (req.headers["x-signature"] as string | undefined);
289→
290→    try {
291→      const result = await handleWebhookTrigger(
292→        workflowId,
293→        rawBody, // Raw body string — used for HMAC verification + passed as triggerData
294→        signature,
295→        signature,
296→        getExecutorRegistry(),
297→      );
298→      json(res, result, 201);
299→    } catch (err) {
300→      if (err instanceof TriggerSchemaError) {
301→        jsonError(res, err.message, 400);
302→      } else if (err instanceof WebhookError) {
303→        jsonError(res, err.message, err.statusCode);
304→      } else {
305→        jsonError(res, String(err), 500);
306→      }
307→    }
308→    return true;
309→  }
310→
311→  // Version history routes must be checked BEFORE single workflow GET
312→  // (since "versions" would match the :id wildcard)
313→  if (getWorkflowVersionRoute.match(req.method, pathSegments)) {
314→    const parsed = await getWorkflowVersionRoute.parse(req, res, pathSegments, queryParams);
315→    if (!parsed) return true;
316→    const version = getWorkflowVersion(parsed.params.id, parsed.params.version);
317→    if (!version) {
318→      res.writeHead(404);
319→      res.end();
320→      return true;
321→    }
322→    json(res, version);
323→    return true;
324→  }
325→
326→  if (listWorkflowVersionsRoute.match(req.method, pathSegments)) {
327→    const parsed = await listWorkflowVersionsRoute.parse(req, res, pathSegments, queryParams);
328→    if (!parsed) return true;
329→    const workflow = getWorkflow(parsed.params.id);
330→    if (!workflow) {
331→      res.writeHead(404);
332→      res.end();
333→      return true;
334→    }
335→    const versions = getWorkflowVersions(parsed.params.id);
336→    json(res, { versions });
337→    return true;
338→  }
339→
340→  if (listWorkflowsRoute.match(req.method, pathSegments)) {
341→    const workflows = listWorkflows();
342→    json(res, workflows);
343→    return true;
344→  }
345→
346→  if (createWorkflowRoute.match(req.method, pathSegments)) {
347→    const parsed = await createWorkflowRoute.parse(req, res, pathSegments, queryParams);
348→    if (!parsed) return true;
349→
350→    // Validate definition structure
351→    const validation = validateDefinition(parsed.body.definition);
352→    if (!validation.valid) {
353→      jsonError(res, `Invalid definition: ${validation.errors.join("; ")}`, 400);
354→      return true;
355→    }
356→
357→    const workflow = createWorkflow({
358→      name: parsed.body.name,
359→      description: parsed.body.description,
360→      definition: parsed.body.definition,
361→      triggers: parsed.body.triggers,
362→      cooldown: parsed.body.cooldown,
363→      input: parsed.body.input,
364→      triggerSchema: parsed.body.triggerSchema,
365→      createdByAgentId: myAgentId ?? undefined,
366→    });
367→    json(res, workflow, 201);
368→    return true;
369→  }
370→
371→  if (getWorkflowRoute.match(req.method, pathSegments)) {
372→    const parsed = await getWorkflowRoute.parse(req, res, pathSegments, queryParams);
373→    if (!parsed) return true;
374→    const workflow = getWorkflow(parsed.params.id);
375→    if (!workflow) {
376→      res.writeHead(404);
377→      res.end();
378→      return true;
379→    }
380→    // Include auto-generated edges for UI rendering
381→    const edges = generateEdges(workflow.definition);
382→    json(res, { ...workflow, edges });
383→    return true;
384→  }
385→
386→  if (updateWorkflowRoute.match(req.method, pathSegments)) {
387→    const parsed = await updateWorkflowRoute.parse(req, res, pathSegments, queryParams);
388→    if (!parsed) return true;
389→    const { id } = parsed.params;
390→    const body = parsed.body;
391→
392→    // Check workflow exists before snapshotting
393→    const existing = getWorkflow(id);
394→    if (!existing) {
395→      res.writeHead(404);
396→      res.end();
397→      return true;
398→    }
399→
400→    // Validate new definition if provided
401→    if (body.definition) {
402→      const validation = validateDefinition(body.definition);
403→      if (!validation.valid) {
404→        jsonError(res, `Invalid definition: ${validation.errors.join("; ")}`, 400);
405→        return true;
406→      }
407→    }
408→
409→    // Create version snapshot before applying update
410→    try {
411→      snapshotWorkflow(id, myAgentId);
412→    } catch {
413→      // Snapshot failure should not block the update — log and continue
414→    }
415→
416→    const workflow = updateWorkflow(id, {
417→      name: body.name,
418→      description: body.description,
419→      definition: body.definition,
420→      triggers: body.triggers,
421→      cooldown: body.cooldown === null ? null : body.cooldown,
422→      input: body.input === null ? null : body.input,
423→      triggerSchema: body.triggerSchema === null ? null : body.triggerSchema,
424→      enabled: body.enabled,
425→    });
426→    if (!workflow) {
427→      res.writeHead(404);
428→      res.end();
429→      return true;
430→    }
431→    json(res, workflow);
432→    return true;
433→  }
434→
435→  if (deleteWorkflowRoute.match(req.method, pathSegments)) {
436→    const parsed = await deleteWorkflowRoute.parse(req, res, pathSegments, queryParams);
437→    if (!parsed) return true;
438→    try {
439→      const deleted = deleteWorkflow(parsed.params.id);
440→      res.writeHead(deleted ? 204 : 404);
441→    } catch (err) {
442→      jsonError(res, String(err), 500);
443→      return true;
444→    }
445→    res.end();
446→    return true;
447→  }
448→
449→  if (triggerWorkflowRoute.match(req.method, pathSegments)) {
450→    const parsed = await triggerWorkflowRoute.parse(req, res, pathSegments, queryParams);
451→    if (!parsed) return true;
452→    const workflow = getWorkflow(parsed.params.id);
453→    if (!workflow) {
454→      res.writeHead(404);
455→      res.end();
456→      return true;
457→    }
458→    if (!workflow.enabled) {
459→      jsonError(res, "Workflow is disabled", 400);
460→      return true;
461→    }
462→    const body = await parseBody<Record<string, unknown>>(req);
463→
464→    let runId: string;
465→    try {
466→      runId = await startWorkflowExecution(workflow, body, getExecutorRegistry());
467→    } catch (err) {
468→      if (err instanceof TriggerSchemaError) {
469→        jsonError(res, err.message, 400);
470→        return true;
471→      }
472→      throw err;
473→    }
474→
475→    // Check if skipped due to cooldown
476→    const run = getWorkflowRun(runId);
477→    const skipped = run?.status === "skipped";
478→
479→    json(res, { runId, skipped }, 201);
480→    return true;
481→  }
482→
483→  if (listWorkflowRunsRoute.match(req.method, pathSegments)) {
484→    const parsed = await listWorkflowRunsRoute.parse(req, res, pathSegments, queryParams);
485→    if (!parsed) return true;
486→    let runs = listWorkflowRuns(parsed.params.id);
487→    // Apply optional status filter
488→    if (parsed.query?.status) {
489→      runs = runs.filter((r) => r.status === parsed.query.status);
490→    }
491→    json(res, runs);
492→    return true;
493→  }
494→
495→  if (getWorkflowRunRoute.match(req.method, pathSegments)) {
496→    const parsed = await getWorkflowRunRoute.parse(req, res, pathSegments, queryParams);
497→    if (!parsed) return true;
498→    const run = getWorkflowRun(parsed.params.id);
499→    if (!run) {
500→      res.writeHead(404);
501→      res.end();
502→      return true;
503→    }
504→    const steps = getWorkflowRunStepsByRunId(parsed.params.id);
505→    json(res, { run, steps });
506→    return true;
507→  }
508→
509→  if (retryWorkflowRunRoute.match(req.method, pathSegments)) {
510→    const parsed = await retryWorkflowRunRoute.parse(req, res, pathSegments, queryParams);
511→    if (!parsed) return true;
512→    try {
513→      await retryFailedRun(parsed.params.id, getExecutorRegistry());
514→      json(res, { success: true });
515→    } catch (err) {
516→      jsonError(res, String(err), 400);
517→    }
518→    return true;
519→  }
520→
521→  return false;
522→}
