 1→import { z } from "zod";
 2→import type { ExecutorMeta } from "../../types";
 3→import type { ExecutorResult } from "./base";
 4→import { BaseExecutor } from "./base";
 5→
 6→// ─── Config / Output Schemas ────────────────────────────────
 7→
 8→const AgentTaskConfigSchema = z.object({
 9→  template: z.string(),
10→  agentId: z.string().uuid().optional(),
11→  tags: z.array(z.string()).optional(),
12→  priority: z.number().int().min(0).max(100).optional(),
13→  offerMode: z.boolean().optional(),
14→  dir: z.string().min(1).optional(),
15→  vcsRepo: z.string().min(1).optional(),
16→  model: z.string().min(1).optional(),
17→  parentTaskId: z.string().uuid().optional(),
18→  outputSchema: z.record(z.string(), z.unknown()).optional(),
19→});
20→
21→const AgentTaskOutputSchema = z.object({
22→  taskId: z.string().uuid(),
23→  taskOutput: z.unknown(),
24→});
25→
26→type AgentTaskOutput = z.infer<typeof AgentTaskOutputSchema>;
27→
28→// ─── Executor ───────────────────────────────────────────────
29→
30→export class AgentTaskExecutor extends BaseExecutor<
31→  typeof AgentTaskConfigSchema,
32→  typeof AgentTaskOutputSchema
33→> {
34→  readonly type = "agent-task";
35→  readonly mode = "async" as const;
36→  readonly configSchema = AgentTaskConfigSchema;
37→  readonly outputSchema = AgentTaskOutputSchema;
38→
39→  protected async execute(
40→    config: z.infer<typeof AgentTaskConfigSchema>,
41→    _context: Readonly<Record<string, unknown>>,
42→    meta: ExecutorMeta,
43→  ): Promise<ExecutorResult<AgentTaskOutput>> {
44→    const { db } = this.deps;
45→
46→    // 1. Idempotency: check if a task was already created for this step
47→    const existingTask = db.getTaskByWorkflowRunStepId(meta.stepId);
48→    if (existingTask) {
49→      if (existingTask.status === "completed") {
50→        return {
51→          status: "success",
52→          output: {
53→            taskId: existingTask.id,
54→            taskOutput: existingTask.output,
55→          },
56→        };
57→      }
58→      // Task exists but not yet completed — return async marker to keep waiting.
59→      // The engine detects async results via `"async" in result`.
60→      return {
61→        status: "success",
62→        async: true,
63→        waitFor: "task.completed",
64→        correlationId: existingTask.id,
65→      } as unknown as ExecutorResult<AgentTaskOutput>;
66→    }
67→
68→    // 2. Create the task (config is already deep-interpolated by the engine)
69→    const task = db.createTaskExtended(config.template, {
70→      agentId: config.agentId ?? null,
71→      source: "workflow",
72→      tags: config.tags,
73→      priority: config.priority,
74→      offeredTo: config.offerMode ? config.agentId : undefined,
75→      workflowRunId: meta.runId,
76→      workflowRunStepId: meta.stepId,
77→      dir: config.dir,
78→      vcsRepo: config.vcsRepo,
79→      model: config.model,
80→      parentTaskId: config.parentTaskId,
81→      outputSchema: config.outputSchema,
82→    });
83→
84→    // 4. Return async result — engine will pause the workflow
85→    return {
86→      status: "success",
87→      async: true,
88→      waitFor: "task.completed",
89→      correlationId: task.id,
90→    } as unknown as ExecutorResult<AgentTaskOutput>;
91→  }
92→}
