  1→import type { ExecutorMeta, WorkflowNode } from "../types";
  2→import type { ExecutorRegistry } from "./executors/registry";
  3→
  4→export type ValidationOutcome = "pass" | "halt" | "retry";
  5→
  6→export interface ValidationRunResult {
  7→  outcome: ValidationOutcome;
  8→  /** Context additions if retry is needed */
  9→  retryContext?: Record<string, unknown>;
 10→}
 11→
 12→/**
 13→ * Normalize executor output to a pass/fail boolean.
 14→ *
 15→ * Different executors use different output shapes to indicate success.
 16→ * This adapter maps each executor type's convention to a uniform boolean.
 17→ */
 18→export function extractPassResult(executorType: string, output: unknown): boolean {
 19→  if (!output || typeof output !== "object") return false;
 20→  const o = output as Record<string, unknown>;
 21→
 22→  switch (executorType) {
 23→    case "validate":
 24→      return o.pass === true;
 25→    case "script":
 26→      return o.exitCode === 0;
 27→    case "property-match":
 28→      return o.passed === true;
 29→    case "raw-llm":
 30→      // For raw-llm used as validator, check if the LLM output contains a structured pass result
 31→      if (typeof o.result === "object" && o.result !== null) {
 32→        return (o.result as Record<string, unknown>).pass === true;
 33→      }
 34→      return false;
 35→    default:
 36→      // Generic fallback: check for common pass indicators
 37→      return o.pass === true || o.passed === true || o.exitCode === 0;
 38→  }
 39→}
 40→
 41→/**
 42→ * Run per-step validation after a step completes.
 43→ *
 44→ * If the node has no validation config, returns "pass" immediately.
 45→ * Otherwise runs the validation executor and returns the outcome.
 46→ */
 47→export async function runStepValidation(
 48→  registry: ExecutorRegistry,
 49→  stepNode: WorkflowNode,
 50→  stepOutput: unknown,
 51→  context: Record<string, unknown>,
 52→  meta: ExecutorMeta,
 53→): Promise<ValidationRunResult> {
 54→  if (!stepNode.validation) {
 55→    return { outcome: "pass" };
 56→  }
 57→
 58→  const validation = stepNode.validation;
 59→  const executorType = validation.executor || "validate";
 60→
 61→  const executor = registry.get(executorType);
 62→  const validationConfig = {
 63→    targetNodeId: meta.nodeId,
 64→    ...validation.config,
 65→  };
 66→
 67→  // Build a context that includes the step output under its nodeId
 68→  const validationContext: Record<string, unknown> = {
 69→    ...context,
 70→    [meta.nodeId]: stepOutput,
 71→  };
 72→
 73→  const result = await executor.run({
 74→    config: validationConfig,
 75→    context: validationContext,
 76→    meta: {
 77→      ...meta,
 78→      stepId: crypto.randomUUID(), // Validation gets its own step ID
 79→    },
 80→  });
 81→
 82→  const passed = result.status === "success" && extractPassResult(executorType, result.output);
 83→
 84→  if (passed) {
 85→    return { outcome: "pass" };
 86→  }
 87→
 88→  // Validation failed
 89→  if (validation.mustPass) {
 90→    if (validation.retry) {
 91→      return {
 92→        outcome: "retry",
 93→        retryContext: {
 94→          previousOutput: stepOutput,
 95→          validationResult: result.output,
 96→        },
 97→      };
 98→    }
 99→    return { outcome: "halt" };
100→  }

  1→import {
  2→  getRetryableSteps,
  3→  getWorkflow,
  4→  getWorkflowRun,
  5→  updateWorkflowRun,
  6→  updateWorkflowRunStep,
  7→} from "../be/db";
  8→import type { RetryPolicy } from "../types";
  9→import { checkpointStep, checkpointStepFailure } from "./checkpoint";
 10→import { getSuccessors } from "./definition";
 11→import { walkGraph } from "./engine";
 12→import type { ExecutorRegistry } from "./executors/registry";
 13→import { deepInterpolate } from "./template";
 14→import { runStepValidation } from "./validation";
 15→
 16→let pollerTimeout: ReturnType<typeof setTimeout> | null = null;
 17→
 18→/**
 19→ * Start the retry poller.
 20→ *
 21→ * Uses setTimeout chaining (not setInterval) to prevent overlap —
 22→ * the next tick is scheduled only after the current one completes.
 23→ */
 24→export function startRetryPoller(registry: ExecutorRegistry, intervalMs = 5000): void {
 25→  if (pollerTimeout !== null) return; // Already running
 26→
 27→  async function poll(): Promise<void> {
 28→    try {
 29→      const retryableSteps = getRetryableSteps();
 30→
 31→      for (const step of retryableSteps) {
 32→        try {
 33→          const run = getWorkflowRun(step.runId);
 34→          if (!run) continue;
 35→
 36→          const workflow = getWorkflow(run.workflowId);
 37→          if (!workflow) continue;
 38→
 39→          // Find the node definition for this step
 40→          const node = workflow.definition.nodes.find((n) => n.id === step.nodeId);
 41→          if (!node) continue;
 42→
 43→          console.log(
 44→            `[workflows] Retrying step ${step.nodeId} (attempt ${step.retryCount}) for run ${step.runId}`,
 45→          );
 46→
 47→          // If the run was failed (due to this step), set it back to running
 48→          if (run.status === "failed") {
 49→            updateWorkflowRun(run.id, {
 50→              status: "running",
 51→              error: undefined,
 52→            });
 53→          }
 54→
 55→          // Clear the retry marker so this step isn't picked up again
 56→          updateWorkflowRunStep(step.id, {
 57→            status: "running",
 58→            error: undefined,
 59→            nextRetryAt: undefined,
 60→          });
 61→
 62→          const ctx = (run.context ?? {}) as Record<string, unknown>;
 63→
 64→          // Deep-interpolate config
 65→          const { value: interpolatedValue } = deepInterpolate(node.config, ctx);
 66→          const interpolatedConfig = interpolatedValue as Record<string, unknown>;
 67→
 68→          // Get executor and re-run
 69→          const executor = registry.get(node.type);
 70→          const meta = {
 71→            runId: run.id,
 72→            stepId: step.id,
 73→            nodeId: step.nodeId,
 74→            workflowId: workflow.id,
 75→            dryRun: false,
 76→          };
 77→
 78→          try {
 79→            const result = await executor.run({
 80→              config: interpolatedConfig,
 81→              context: ctx,
 82→              meta,
 83→            });
 84→
 85→            if (result.status === "failed") {
 86→              // Re-failed — use the EXISTING retryCount from the step.
 87→              // checkpointStepFailure handles marking run as failed if no retries left,
 88→              // or setting nextRetryAt for the next poll cycle.
 89→              const retryPolicy = node.retry || executor.retryPolicy;
 90→              checkpointStepFailure(
 91→                run.id,
 92→                step.id,
 93→                result.error || "Retry failed",
 94→                step.retryCount,
 95→                retryPolicy,
 96→              );
 97→            } else {
 98→              // Success! Re-run validation if configured before checkpointing.
 99→              if (node.validation) {
100→                const validationResult = await runStepValidation(
101→                  registry,
102→                  node,
103→                  result.output,
