 1→/**
 2→ * Minimal hand-rolled JSON Schema validator.
 3→ *
 4→ * Supports the subset needed for workflow I/O schemas:
 5→ * - `type`: "object", "string", "number", "boolean", "array"
 6→ * - `required`: array of required property names
 7→ * - `properties`: map of property name → schema (recursive)
 8→ *
 9→ * Returns an array of validation error strings (empty = valid).
10→ */
11→export function validateJsonSchema(schema: Record<string, unknown>, data: unknown): string[] {
12→  const errors: string[] = [];
13→  validate(schema, data, "", errors);
14→  return errors;
15→}
16→
17→function validate(
18→  schema: Record<string, unknown>,
19→  data: unknown,
20→  path: string,
21→  errors: string[],
22→): void {
23→  const prefix = path || "root";
24→
25→  // Type check
26→  if (schema.type !== undefined) {
27→    const expected = schema.type as string;
28→    if (!matchesType(expected, data)) {
29→      errors.push(`${prefix}: expected type "${expected}", got ${typeOf(data)}`);
30→      return; // No point checking properties of wrong type
31→    }
32→  }
33→
34→  // Required fields (only for objects)
35→  if (Array.isArray(schema.required) && typeof data === "object" && data !== null) {
36→    const obj = data as Record<string, unknown>;
37→    for (const key of schema.required as string[]) {
38→      if (!(key in obj)) {
39→        errors.push(`${prefix}: missing required property "${key}"`);
40→      }
41→    }
42→  }
43→
44→  // Enum check
45→  if (Array.isArray(schema.enum)) {
46→    const allowed = schema.enum as unknown[];
47→    if (!allowed.some((v) => JSON.stringify(v) === JSON.stringify(data))) {
48→      errors.push(
49→        `${prefix}: value ${JSON.stringify(data)} not in enum [${allowed.map((v) => JSON.stringify(v)).join(", ")}]`,
50→      );
51→      return;
52→    }
53→  }
54→
55→  // Const check
56→  if ("const" in schema) {
57→    if (JSON.stringify(data) !== JSON.stringify(schema.const)) {
58→      errors.push(
59→        `${prefix}: value ${JSON.stringify(data)} does not match const ${JSON.stringify(schema.const)}`,
60→      );
61→      return;
62→    }
63→  }
64→
65→  // Recursive property validation (only for objects)
66→  if (
67→    schema.properties !== undefined &&
68→    typeof schema.properties === "object" &&
69→    schema.properties !== null &&
70→    typeof data === "object" &&
71→    data !== null
72→  ) {
73→    const props = schema.properties as Record<string, Record<string, unknown>>;
74→    const obj = data as Record<string, unknown>;
75→    for (const [key, subSchema] of Object.entries(props)) {
76→      if (key in obj) {
77→        validate(subSchema, obj[key], path ? `${path}.${key}` : key, errors);
78→      }
79→    }
80→  }

 1→/**
 2→ * Replace {{path.to.value}} tokens in a template string
 3→ * with values from the context object.
 4→ *
 5→ * Returns the interpolated result and a list of any unresolved token paths.
 6→ */
 7→
 8→export interface InterpolateResult {
 9→  result: string;
10→  unresolved: string[];
11→}
12→
13→export function interpolate(template: string, ctx: Record<string, unknown>): InterpolateResult {
14→  const unresolved: string[] = [];
15→  const result = template.replace(/\{\{([^}]+)\}\}/g, (_match, path: string) => {
16→    const keys = path.trim().split(".");
17→    let value: unknown = ctx;
18→    for (const key of keys) {
19→      if (value == null || typeof value !== "object") {
20→        unresolved.push(path.trim());
21→        return "";
22→      }
23→      value = (value as Record<string, unknown>)[key];
24→    }
25→    if (value == null) {
26→      unresolved.push(path.trim());
27→      return "";
28→    }
29→    return typeof value === "object" ? safeStringify(value) : String(value);
30→  });
31→  return { result, unresolved };
32→}
33→
34→/**
35→ * Circular-reference-safe JSON.stringify for interpolation.
36→ * Returns "[Circular]" instead of throwing on circular structures.
37→ */
38→function safeStringify(value: unknown): string {
39→  try {
40→    return JSON.stringify(value);
41→  } catch {
42→    return "[Circular]";
43→  }
44→}
45→
46→/**
47→ * Deep-interpolate an arbitrary value tree (objects, arrays, strings).
48→ * Non-string leaves are passed through unchanged.
49→ */
50→export function deepInterpolate(
51→  value: unknown,
52→  ctx: Record<string, unknown>,
53→): { value: unknown; unresolved: string[] } {
54→  const allUnresolved: string[] = [];
55→
56→  function walk(v: unknown): unknown {
57→    if (typeof v === "string") {
58→      const { result, unresolved } = interpolate(v, ctx);
59→      allUnresolved.push(...unresolved);
60→      return result;
61→    }
62→    if (Array.isArray(v)) return v.map(walk);
63→    if (v != null && typeof v === "object") {
64→      const out: Record<string, unknown> = {};
65→      for (const [k, val] of Object.entries(v)) {
66→        out[k] = walk(val);
67→      }
68→      return out;
69→    }
70→    return v;
71→  }
72→
73→  return { value: walk(value), unresolved: allUnresolved };
74→}
