 1→import { z } from "zod";
 2→import { AgentTaskExecutor } from "./agent-task";
 3→import type { BaseExecutor, ExecutorDependencies } from "./base";
 4→import { CodeMatchExecutor } from "./code-match";
 5→import { NotifyExecutor } from "./notify";
 6→import { PropertyMatchExecutor } from "./property-match";
 7→import { RawLlmExecutor } from "./raw-llm";
 8→import { ScriptExecutor } from "./script";
 9→import { ValidateExecutor } from "./validate";
10→import { VcsExecutor } from "./vcs";
11→
12→export interface ExecutorTypeInfo {
13→  type: string;
14→  mode: "instant" | "async";
15→  configSchema: Record<string, unknown>;
16→  outputSchema: Record<string, unknown>;
17→}
18→
19→export class ExecutorRegistry {
20→  private executors = new Map<string, BaseExecutor>();
21→
22→  register(executor: BaseExecutor): void {
23→    this.executors.set(executor.type, executor);
24→  }
25→
26→  get(type: string): BaseExecutor {
27→    const executor = this.executors.get(type);
28→    if (!executor) throw new Error(`Unknown executor type: ${type}`);
29→    return executor;
30→  }
31→
32→  has(type: string): boolean {
33→    return this.executors.has(type);
34→  }
35→
36→  types(): string[] {
37→    return [...this.executors.keys()];
38→  }
39→
40→  /** Return JSON Schema metadata for a single executor type */
41→  describe(type: string): ExecutorTypeInfo {
42→    const executor = this.get(type);
43→    return {
44→      type: executor.type,
45→      mode: executor.mode,
46→      configSchema: z.toJSONSchema(executor.configSchema) as Record<string, unknown>,
47→      outputSchema: z.toJSONSchema(executor.outputSchema) as Record<string, unknown>,
48→    };
49→  }
50→
51→  /** Return JSON Schema metadata for all executor types */
52→  describeAll(): ExecutorTypeInfo[] {
53→    return this.types().map((t) => this.describe(t));
54→  }
55→}
56→
57→/**
58→ * Create an executor registry with all built-in executors registered.
59→ */
60→export function createExecutorRegistry(deps: ExecutorDependencies): ExecutorRegistry {
61→  const registry = new ExecutorRegistry();
62→
63→  // Instant executors (Phase 2)
64→  registry.register(new PropertyMatchExecutor(deps));
65→  registry.register(new CodeMatchExecutor(deps));
66→  registry.register(new NotifyExecutor(deps));
67→  registry.register(new RawLlmExecutor(deps));
68→  registry.register(new ScriptExecutor(deps));
69→  registry.register(new VcsExecutor(deps));
70→  registry.register(new ValidateExecutor(deps));
71→
72→  // Async executors (Phase 4)
73→  registry.register(new AgentTaskExecutor(deps));
74→
75→  return registry;
76→}
