 1→import { getSwarmConfigs } from "../be/db";
 2→
 3→/**
 4→ * Resolve workflow input values.
 5→ *
 6→ * Patterns:
 7→ *   - `${ENV_VAR}` -> process.env[ENV_VAR]
 8→ *   - `secret.NAME` -> look up in DB config store (global scope, isSecret=true)
 9→ *   - literal string -> pass through
10→ */
11→export function resolveInputs(input: Record<string, string>): Record<string, string> {
12→  const resolved: Record<string, string> = {};
13→
14→  for (const [key, value] of Object.entries(input)) {
15→    resolved[key] = resolveValue(value);
16→  }
17→
18→  return resolved;
19→}
20→
21→function resolveValue(value: string): string {
22→  // Env var reference: ${MY_VAR}
23→  const envMatch = /^\$\{(.+)\}$/.exec(value);
24→  if (envMatch?.[1]) {
25→    const envName = envMatch[1];
26→    const envValue = process.env[envName];
27→    if (envValue === undefined) {
28→      throw new Error(`Environment variable "${envName}" is not set`);
29→    }
30→    return envValue;
31→  }
32→
33→  // Secret reference: secret.NAME
34→  if (value.startsWith("secret.")) {
35→    const secretName = value.slice("secret.".length);
36→    const configs = getSwarmConfigs({ scope: "global", key: secretName });
37→    const secretConfig = configs.find((c) => c.isSecret);
38→    if (!secretConfig) {
39→      throw new Error(`Secret "${secretName}" not found in config store`);
40→    }
41→    return secretConfig.value;
42→  }
43→
44→  // Literal
45→  return value;
46→}
