 1→import type { ZodType, z } from "zod";
 2→import type { ExecutorMeta, RetryPolicy } from "../../types";
 3→import type { WorkflowEventBus } from "../event-bus";
 4→
 5→// ─── Dependencies ──────────────────────────────────────────
 6→
 7→export interface ExecutorDependencies {
 8→  db: typeof import("../../be/db");
 9→  eventBus: WorkflowEventBus;
10→  interpolate: (template: string, ctx: Record<string, unknown>) => string;
11→}
12→
13→// ─── Input / Result Types ──────────────────────────────────
14→
15→export interface ExecutorInput {
16→  config: Record<string, unknown>;
17→  context: Readonly<Record<string, unknown>>;
18→  meta: ExecutorMeta;
19→}
20→
21→export interface ExecutorResult<TOutput = unknown> {
22→  status: "success" | "failed" | "skipped";
23→  output?: TOutput;
24→  nextPort?: string;
25→  error?: string;
26→}
27→
28→export interface AsyncExecutorResult<TOutput = unknown> extends ExecutorResult<TOutput> {
29→  async: true;
30→  waitFor: string;
31→  correlationId: string;
32→}
33→
34→// ─── Base Executor ─────────────────────────────────────────
35→
36→export abstract class BaseExecutor<
37→  TConfig extends ZodType = ZodType,
38→  TOutput extends ZodType = ZodType,
39→> {
40→  abstract readonly type: string;
41→  abstract readonly mode: "instant" | "async";
42→  abstract readonly configSchema: TConfig;
43→  abstract readonly outputSchema: TOutput;
44→
45→  /** Optional default retry policy — can be overridden per node */
46→  readonly retryPolicy?: RetryPolicy;
47→
48→  constructor(protected readonly deps: ExecutorDependencies) {}
49→
50→  /**
51→   * Validate config, execute, validate output.
52→   * Catches Zod validation errors at both boundaries.
53→   */
54→  async run(input: ExecutorInput): Promise<ExecutorResult<z.infer<TOutput>>> {
55→    // Validate input config
56→    const configResult = this.configSchema.safeParse(input.config);
57→    if (!configResult.success) {
58→      return {
59→        status: "failed",
60→        error: `Input validation failed: ${configResult.error.message}`,
61→      };
62→    }
63→
64→    const result = await this.execute(configResult.data, input.context, input.meta);
65→
66→    // Validate output for successful results
67→    if (result.status === "success" && result.output !== undefined) {
68→      const outputResult = this.outputSchema.safeParse(result.output);
69→      if (!outputResult.success) {
70→        return {
71→          status: "failed",
72→          error: `Output validation failed: ${outputResult.error.message}`,
73→        };
74→      }
75→    }
76→
77→    return result;
78→  }
79→
80→  /** Implement this in each executor */
81→  protected abstract execute(
82→    config: z.infer<TConfig>,
83→    context: Readonly<Record<string, unknown>>,
84→    meta: ExecutorMeta,
85→  ): Promise<ExecutorResult<z.infer<TOutput>>>;
86→}
