  1→import {
  2→  getWorkflow,
  3→  getWorkflowRun,
  4→  getWorkflowRunStep,
  5→  getWorkflowRunStepsByRunId,
  6→  updateWorkflowRun,
  7→  updateWorkflowRunStep,
  8→} from "../be/db";
  9→import { checkpointStep } from "./checkpoint";
 10→import { getSuccessors } from "./definition";
 11→import { walkGraph } from "./engine";
 12→import type { WorkflowEventBus } from "./event-bus";
 13→import type { ExecutorRegistry } from "./executors/registry";
 14→
 15→interface TaskEvent {
 16→  taskId: string;
 17→  output?: string;
 18→  agentId?: string;
 19→  workflowRunId?: string;
 20→  workflowRunStepId?: string;
 21→  failureReason?: string;
 22→}
 23→
 24→/**
 25→ * Wire up event bus listeners for workflow resume on task lifecycle events.
 26→ */
 27→export function setupWorkflowResumeListener(
 28→  eventBus: WorkflowEventBus,
 29→  registry: ExecutorRegistry,
 30→): void {
 31→  eventBus.on("task.completed", async (data: unknown) => {
 32→    const event = data as TaskEvent;
 33→    if (!event.workflowRunId || !event.workflowRunStepId) return;
 34→    try {
 35→      await resumeFromTaskCompletion(event, registry);
 36→    } catch (err) {
 37→      console.error("[workflows] Resume from task completion failed:", err);
 38→    }
 39→  });
 40→
 41→  eventBus.on("task.failed", async (data: unknown) => {
 42→    const event = data as TaskEvent;
 43→    if (!event.workflowRunId || !event.workflowRunStepId) return;
 44→    markRunFailed(event, event.failureReason ?? "Task failed");
 45→  });
 46→
 47→  eventBus.on("task.cancelled", async (data: unknown) => {
 48→    const event = data as TaskEvent;
 49→    if (!event.workflowRunId || !event.workflowRunStepId) return;
 50→    markRunFailed(event, "Task was cancelled");
 51→  });
 52→}
 53→
 54→/**
 55→ * Resume a workflow after a linked task completes.
 56→ *
 57→ * 1. Verify run and step are in "waiting" state
 58→ * 2. Checkpoint step completion with task output
 59→ * 3. Set run status to "running"
 60→ * 4. Find successors and continue the graph walk
 61→ */
 62→async function resumeFromTaskCompletion(
 63→  event: TaskEvent,
 64→  registry: ExecutorRegistry,
 65→): Promise<void> {
 66→  const run = getWorkflowRun(event.workflowRunId!);
 67→  if (!run || run.status !== "waiting") return;
 68→
 69→  const step = getWorkflowRunStep(event.workflowRunStepId!);
 70→  if (!step || step.status !== "waiting") return;
 71→
 72→  const workflow = getWorkflow(run.workflowId);
 73→  if (!workflow) return;
 74→
 75→  // Checkpoint: atomic step completion + context update
 76→  const ctx = (run.context ?? {}) as Record<string, unknown>;
 77→
 78→  // JSON-parse structured output so downstream nodes can access nested fields
 79→  let taskOutput: unknown = event.output;
 80→  if (event.output) {
 81→    try {
 82→      const parsed = JSON.parse(event.output);
 83→      if (typeof parsed === "object" && parsed !== null) {
 84→        taskOutput = parsed;
 85→      }
 86→    } catch {
 87→      // Not JSON — keep as string (non-structured output tasks)
 88→    }
 89→  }
 90→  const stepOutput = { taskId: event.taskId, taskOutput };
 91→
 92→  checkpointStep(run.id, step.id, step.nodeId, { output: stepOutput }, ctx);
 93→
 94→  // Set run back to running
 95→  updateWorkflowRun(run.id, { status: "running" });
 96→
 97→  // Find successors and continue DAG walk
 98→  const successors = getSuccessors(workflow.definition, step.nodeId, "default");
 99→  await walkGraph(workflow.definition, run.id, ctx, successors, registry, workflow.id);
100→}
101→
102→/**
103→ * Mark a workflow run as failed when its linked task fails or is cancelled.
104→ */
