  1→import {
  2→  createWorkflowRun,
  3→  createWorkflowRunStep,
  4→  getCompletedStepNodeIds,
  5→  getStepByIdempotencyKey,
  6→  getWorkflowRun,
  7→  getWorkflowRunStepsByRunId,
  8→  updateWorkflowRun,
  9→  updateWorkflowRunStep,
 10→} from "../be/db";
 11→import type { Workflow, WorkflowDefinition, WorkflowNode } from "../types";
 12→import { checkpointStep, checkpointStepFailure, checkpointStepWaiting } from "./checkpoint";
 13→import { shouldSkipCooldown } from "./cooldown";
 14→import { findEntryNodes, getSuccessors } from "./definition";
 15→import type { AsyncExecutorResult } from "./executors/base";
 16→import type { ExecutorRegistry } from "./executors/registry";
 17→import { resolveInputs } from "./input";
 18→import { validateJsonSchema } from "./json-schema-validator";
 19→import { deepInterpolate } from "./template";
 20→import { runStepValidation } from "./validation";
 21→
 22→const DEFAULT_TIMEOUT_MS = 30_000;
 23→const MAX_ITERATIONS = Number(process.env.WORKFLOW_MAX_ITERATIONS) || 100;
 24→
 25→/**
 26→ * Error thrown when trigger data fails validation against a workflow's triggerSchema.
 27→ */
 28→export class TriggerSchemaError extends Error {
 29→  constructor(public readonly validationErrors: string[]) {
 30→    super(`Trigger schema validation failed: ${validationErrors.join("; ")}`);
 31→    this.name = "TriggerSchemaError";
 32→  }
 33→}
 34→
 35→// ─── Public API ────────────────────────────────────────────
 36→
 37→/**
 38→ * Start executing a workflow from scratch.
 39→ *
 40→ * 1. Check cooldown
 41→ * 2. Create workflow run
 42→ * 3. Resolve inputs
 43→ * 4. Find entry nodes
 44→ * 5. Walk the graph
 45→ */
 46→export async function startWorkflowExecution(
 47→  workflow: Workflow,
 48→  triggerData: unknown,
 49→  registry: ExecutorRegistry,
 50→): Promise<string> {
 51→  // Validate trigger data against triggerSchema (before any DB writes)
 52→  if (workflow.triggerSchema) {
 53→    const validationErrors = validateJsonSchema(workflow.triggerSchema, triggerData);
 54→    if (validationErrors.length > 0) {
 55→      throw new TriggerSchemaError(validationErrors);
 56→    }
 57→  }
 58→
 59→  // Cooldown check
 60→  if (workflow.cooldown && shouldSkipCooldown(workflow.id, workflow.cooldown)) {
 61→    const runId = crypto.randomUUID();
 62→    createWorkflowRun({ id: runId, workflowId: workflow.id, triggerData });
 63→    updateWorkflowRun(runId, {
 64→      status: "skipped",
 65→      error: "cooldown",
 66→      finishedAt: new Date().toISOString(),
 67→    });
 68→    return runId;
 69→  }
 70→
 71→  const runId = crypto.randomUUID();
 72→  createWorkflowRun({ id: runId, workflowId: workflow.id, triggerData });
 73→
 74→  // Resolve inputs and merge into initial context
 75→  const ctx: Record<string, unknown> = { trigger: triggerData };
 76→  if (workflow.input) {
 77→    try {
 78→      const resolved = resolveInputs(workflow.input);
 79→      Object.assign(ctx, { input: resolved });
 80→    } catch (err) {
 81→      updateWorkflowRun(runId, {
 82→        status: "failed",
 83→        error: `Input resolution failed: ${err}`,
 84→        finishedAt: new Date().toISOString(),
 85→      });
 86→      return runId;
 87→    }
 88→  }
 89→
 90→  const entryNodes = findEntryNodes(workflow.definition);
 91→  await walkGraph(workflow.definition, runId, ctx, entryNodes, registry, workflow.id);
 92→  return runId;
 93→}
 94→
 95→// ─── Graph Walker ──────────────────────────────────────────
 96→
 97→/**
 98→ * Step execution result — includes the successors to queue next.
 99→ */
100→interface StepResult {
101→  outcome: "completed" | "waiting" | "failed";
102→  successors: WorkflowNode[];
103→}
104→
105→/**
106→ * Event-loop style graph walker.
107→ *
108→ * Executes start nodes, collects successor nodes from each completed step's
109→ * port-based routing, deduplicates convergence nodes (waiting for all
110→ * predecessors), then executes the next batch. Repeats until done.
111→ */
112→export async function walkGraph(
113→  def: WorkflowDefinition,
114→  runId: string,
115→  ctx: Record<string, unknown>,
116→  startNodes: WorkflowNode[],
117→  registry: ExecutorRegistry,
118→  workflowId?: string,
119→): Promise<void> {
120→  let nodeExecutionCount = 0;
121→  const completedNodeIds = new Set(getCompletedStepNodeIds(runId));
122→
123→  // Track active edges: "sourceId→targetId" — only edges on actually-taken
124→  // execution paths, not all structural edges in the definition.
125→  const activeEdges = new Set<string>();
126→
127→  // For memoized re-walks, inject stored outputs into context and
128→  // reconstruct active edges from completed steps' stored nextPort.
129→  if (completedNodeIds.size > 0) {
130→    for (const nodeId of completedNodeIds) {
131→      const key = `${runId}:${nodeId}`;
132→      const step = getStepByIdempotencyKey(key);
133→      if (step?.output !== undefined) {
134→        // Bug 5 fix: Validate stored output against executor schema on recovery
135→        const node = def.nodes.find((n) => n.id === nodeId);
136→        if (node && registry.has(node.type)) {
137→          const executor = registry.get(node.type);
138→          const parseResult = executor.outputSchema.safeParse(step.output);
139→          if (!parseResult.success) {
140→            console.warn(
141→              `[workflow] Recovery: step ${nodeId} output failed validation: ${parseResult.error.message}`,
142→            );
143→            continue; // Skip corrupted output
144→          }
145→        }
146→        ctx[nodeId] = step.output;
147→      }
148→      // Reconstruct active edges from the stored nextPort.
149→      // If nextPort is set, use it for port-specific routing.
150→      // If not set, get all successors (fan-out).
151→      const successors = step?.nextPort
152→        ? getSuccessors(def, nodeId, step.nextPort)
153→        : getSuccessors(def, nodeId);
154→      for (const succ of successors) {
155→        activeEdges.add(`${nodeId}→${succ.id}`);
156→      }
157→    }
158→  }
159→
160→  // Seed with start nodes that haven't been completed yet
161→  let pendingNodes = startNodes.filter((n) => !completedNodeIds.has(n.id));
162→
163→  while (pendingNodes.length > 0) {
164→    nodeExecutionCount += pendingNodes.length;
165→    if (nodeExecutionCount > MAX_ITERATIONS) {
166→      updateWorkflowRun(runId, {
167→        status: "failed",
168→        error: `Max node executions (${MAX_ITERATIONS}) exceeded — possible infinite loop`,
169→        finishedAt: new Date().toISOString(),
170→      });
171→      return;
172→    }
173→
174→    // Execute all pending nodes in parallel
175→    const results = await Promise.all(
176→      pendingNodes.map((node) =>
177→        executeStep(def, runId, ctx, node, registry, workflowId).catch(
178→          (_err): StepResult => ({
179→            outcome: "failed",
180→            successors: [],
181→          }),
182→        ),
183→      ),
184→    );
185→
186→    // Collect successors and check for errors/pauses
187→    const nextBatch = new Map<string, WorkflowNode>();
188→    let hasWaiting = false;
189→    let hasFailed = false;
190→
191→    for (let i = 0; i < results.length; i++) {
192→      const result = results[i]!;
193→      if (result.outcome === "failed") {
194→        hasFailed = true;
195→        break;
196→      }
197→      if (result.outcome === "waiting") {
198→        hasWaiting = true;
199→        continue;
200→      }
201→      // Mark this node as completed
202→      const sourceNodeId = pendingNodes[i]!.id;
203→      completedNodeIds.add(sourceNodeId);
204→      // Record active edges and queue successors
205→      for (const succ of result.successors) {
206→        activeEdges.add(`${sourceNodeId}→${succ.id}`);
207→        nextBatch.set(succ.id, succ);
208→      }
209→    }
210→
211→    if (hasFailed) return; // Run already marked failed in executeStep
212→    if (hasWaiting) return; // Run paused, will be resumed by event
213→
214→    // Convergence check — only wait for predecessors with active edges to
215→    // this node, not all structural predecessors. This prevents deadlocks
216→    // when conditional branches skip nodes.
217→    const readyNext: WorkflowNode[] = [];
218→    for (const [nodeId, node] of nextBatch) {
219→      if (completedNodeIds.has(nodeId)) continue; // Already done
220→
221→      const allPreds = getAllPredecessors(def, nodeId);
222→      const activePreds = allPreds.filter((predId) => activeEdges.has(`${predId}→${nodeId}`));
223→      const allActivePredsCompleted = activePreds.every((p) => completedNodeIds.has(p));
224→
225→      if (allActivePredsCompleted) {
226→        readyNext.push(node);
227→      }
228→    }
229→
230→    pendingNodes = readyNext;
231→  }
232→
233→  // No more nodes to execute — check if the run should be completed.
234→  // If any step has a pending retry (failed with nextRetryAt), the run
235→  // should stay in "running" state for the retry poller to pick up.
236→  const run = getWorkflowRun(runId);
237→  if (run && run.status === "running") {
238→    const allSteps = getWorkflowRunStepsByRunId(runId);
239→    const hasPendingRetries = allSteps.some((s) => s.status === "failed" && s.nextRetryAt != null);
240→
241→    if (!hasPendingRetries) {
242→      updateWorkflowRun(runId, {
243→        status: "completed",
244→        context: ctx,
245→        finishedAt: new Date().toISOString(),
246→      });
247→    }
248→  }
249→}
250→
251→/**
252→ * Get all predecessor node IDs for a given node.
253→ * A predecessor is any node that references this node via its `next` field.
254→ */
255→function getAllPredecessors(def: WorkflowDefinition, nodeId: string): string[] {
256→  const preds: string[] = [];
257→  for (const node of def.nodes) {
258→    if (!node.next) continue;
259→    const targets = typeof node.next === "string" ? [node.next] : Object.values(node.next);
260→    if (targets.includes(nodeId)) {
261→      preds.push(node.id);
262→    }
263→  }
264→  return preds;
265→}
266→
267→// ─── Step Execution ────────────────────────────────────────
268→
269→/**
270→ * Execute a single node step:
271→ * 1. Check memoization (idempotency)
272→ * 2. Create step record
273→ * 3. Interpolate config
274→ * 4. Run executor with timeout
275→ * 5. Handle result (checkpoint, validation, or async)
276→ *
277→ * Returns the outcome and list of successor nodes to queue.
278→ */
279→async function executeStep(
280→  def: WorkflowDefinition,
281→  runId: string,
282→  ctx: Record<string, unknown>,
283→  node: WorkflowNode,
284→  registry: ExecutorRegistry,
285→  workflowId?: string,
286→): Promise<StepResult> {
287→  const idempotencyKey = `${runId}:${node.id}`;
288→
289→  // 1. Memoization check
290→  const existingStep = getStepByIdempotencyKey(idempotencyKey);
291→  if (existingStep && existingStep.status === "completed") {
292→    // Inject stored output into context
293→    ctx[node.id] = existingStep.output;
294→    // For memoized steps, return all successors (no port — use default)
295→    const successors = getSuccessors(def, node.id);
296→    return { outcome: "completed", successors };
297→  }
298→
299→  // 2. Create step
300→  const stepId = crypto.randomUUID();
301→  createWorkflowRunStep({
302→    id: stepId,
303→    runId,
304→    nodeId: node.id,
305→    nodeType: node.type,
306→    input: ctx,
307→  });
308→
309→  // Set idempotency key
310→  updateWorkflowRunStep(stepId, { idempotencyKey });
311→
312→  // 3. Get executor
313→  const executor = registry.get(node.type);
314→
315→  // 3b. Build local interpolation context from explicit inputs mapping
316→  let interpolationCtx: Record<string, unknown>;
317→  if (node.inputs) {
318→    interpolationCtx = {};
319→    // Always include built-in sources
320→    if (ctx.trigger !== undefined) interpolationCtx.trigger = ctx.trigger;
321→    if (ctx.input !== undefined) interpolationCtx.input = ctx.input;
322→    // Resolve declared inputs
323→    for (const [localName, sourcePath] of Object.entries(node.inputs)) {
324→      const keys = sourcePath.split(".");
325→      let value: unknown = ctx;
326→      for (const key of keys) {
327→        if (value == null || typeof value !== "object") {
328→          value = undefined;
329→          break;
330→        }
331→        value = (value as Record<string, unknown>)[key];
332→      }
333→      interpolationCtx[localName] = value;
334→    }
335→  } else {
336→    // No inputs declared — only built-in sources available
337→    interpolationCtx = {};
338→    if (ctx.trigger !== undefined) interpolationCtx.trigger = ctx.trigger;
339→    if (ctx.input !== undefined) interpolationCtx.input = ctx.input;
340→  }
341→
342→  // 3c. Validate resolved inputs against inputSchema if defined
343→  if (node.inputSchema) {
344→    const inputErrors = validateJsonSchema(
345→      node.inputSchema as Record<string, unknown>,
346→      interpolationCtx,
347→    );
348→    if (inputErrors.length > 0) {
349→      const errorMsg = `Input schema validation failed: ${inputErrors.join("; ")}`;
350→      checkpointStepFailure(runId, stepId, errorMsg, 0);
351→      throw new Error(errorMsg);
352→    }
353→  }
354→
355→  // 4. Deep-interpolate config using local context (not global ctx)
356→  const { value: interpolatedValue, unresolved } = deepInterpolate(node.config, interpolationCtx);
357→  const interpolatedConfig = interpolatedValue as Record<string, unknown>;
358→
359→  if (unresolved.length > 0) {
360→    console.warn(
361→      `[workflow] Step ${node.id}: unresolved interpolation tokens: ${unresolved.join(", ")}`,
362→    );
363→    updateWorkflowRunStep(stepId, {
364→      diagnostics: JSON.stringify({ unresolvedTokens: unresolved }),
365→    });
366→  }
367→
368→  // 5. Execute with timeout
369→  const meta = {
370→    runId,
371→    stepId,
372→    nodeId: node.id,
373→    workflowId: workflowId || "",
374→    dryRun: false,
375→  };
376→
377→  const timeoutMs = DEFAULT_TIMEOUT_MS;
378→
379→  let result: Awaited<ReturnType<typeof executor.run>>;
380→  try {
381→    result = await Promise.race([
382→      executor.run({
383→        config: interpolatedConfig,
384→        context: ctx,
385→        meta,
386→      }),
387→      timeoutPromise(timeoutMs),
388→    ]);
389→  } catch (err) {
390→    const errorMsg = err instanceof Error ? err.message : String(err);
391→
392→    // Apply retry policy if configured
393→    const retryPolicy = node.retry || executor.retryPolicy;
394→    const currentRetryCount = existingStep?.retryCount || 0;
395→    const { shouldRetry } = checkpointStepFailure(
396→      runId,
397→      stepId,
398→      errorMsg,
399→      currentRetryCount,
400→      retryPolicy,
401→    );
402→
403→    if (!shouldRetry) {
404→      throw err; // Will be caught by walkGraph
405→    }
406→    // Retry will be handled by the retry poller
407→    return { outcome: "completed", successors: [] };
408→  }
409→
410→  // 6. Handle result
411→  if (result.status === "failed") {
412→    const retryPolicy = node.retry || executor.retryPolicy;
413→    const currentRetryCount = existingStep?.retryCount || 0;
414→    const { shouldRetry } = checkpointStepFailure(
415→      runId,
416→      stepId,
417→      result.error || "Executor returned failed status",
418→      currentRetryCount,
419→      retryPolicy,
420→    );
421→
422→    if (!shouldRetry) {
423→      throw new Error(result.error || "Step execution failed");
424→    }
425→    return { outcome: "completed", successors: [] }; // Retry handled by poller
426→  }
427→
428→  // Check for async result
429→  if ("async" in result && (result as AsyncExecutorResult).async) {
430→    checkpointStepWaiting(runId, stepId, ctx);
431→    return { outcome: "waiting", successors: [] };
432→  }
433→
434→  // 6b. Validate output against node-level outputSchema if defined
435→  if (node.outputSchema && result.status === "success") {
436→    const outputErrors = validateJsonSchema(
437→      node.outputSchema as Record<string, unknown>,
438→      result.output,
439→    );
440→    if (outputErrors.length > 0) {
441→      const errorMsg = `Output schema validation failed: ${outputErrors.join("; ")}`;
442→      checkpointStepFailure(runId, stepId, errorMsg, 0);
443→      throw new Error(errorMsg);
444→    }
445→  }
446→
447→  // 7. Run validation if configured
448→  if (node.validation) {
449→    const validationResult = await runStepValidation(registry, node, result.output, ctx, meta);
450→
451→    if (validationResult.outcome === "halt") {
452→      const errorMsg = "Validation failed (mustPass)";
453→      checkpointStepFailure(runId, stepId, errorMsg, 0);
454→      throw new Error(errorMsg);
455→    }
456→
457→    if (validationResult.outcome === "retry") {
458→      // Bug 7 fix: Append validation context to history array instead of overwriting
459→      if (validationResult.retryContext) {
460→        const historyKey = `${node.id}_validations`;
461→        const existing = (ctx[historyKey] as unknown[]) || [];
462→        ctx[historyKey] = [...existing, validationResult.retryContext];
463→      }
464→      const retryPolicy = node.validation.retry || node.retry;
465→      const currentRetryCount = existingStep?.retryCount || 0;
466→      checkpointStepFailure(
467→        runId,
468→        stepId,
