export const WorkflowNodeSchema = z.object({
  id: z.string().describe("Unique node identifier, used to reference this node in 'next' and 'inputs' mappings"),
  type: z.string().describe("Executor type (e.g. 'agent-task', 'script', 'raw-llm', 'validate', 'property-match')"),
  label: z.string().optional().describe("Human-readable label for UI display"),
  config: z.record(z.string(), z.unknown()).describe(
    "Executor-specific configuration. For agent-task: { template, outputSchema?, agentId?, tags?, priority?, dir?, vcsRepo?, model? }. " +
      "Values support {{interpolation}} from the node's inputs context. " +
      "IMPORTANT: config.outputSchema on agent-task nodes validates the AGENT's raw JSON output (e.g. {city: string}), " +
      "while node-level outputSchema validates the EXECUTOR's return value ({taskId, taskOutput}).",
  ),
  next: z.union([z.string(), z.record(z.string(), z.string())]).optional().describe(
    "Next node(s): a string for simple chaining ('next-node-id') or a record for port-based routing ({pass: 'node-a', fail: 'node-b'})",
  ),
  validation: StepValidationConfigSchema.optional(),
  retry: RetryPolicySchema.optional(),
  // Explicit data mapping: local name → context path (e.g. {prNum: "trigger.prNumber"})
  inputs: z
    .record(z.string(), z.string())
    .optional()
    .describe(
      "REQUIRED for cross-node data access. Maps local names to context paths. " +
        "Without this, only 'trigger' and 'input' are available for interpolation — upstream step outputs are NOT accessible. " +
        "Example: { \"cityData\": \"generate-city\" } makes step 'generate-city' output available as {{cityData.taskOutput.field}}. " +
        "For trigger data: { \"pr\": \"trigger.pullRequest\" }.",
    ),
  // JSON Schema for input validation (validated after inputs resolution)
  inputSchema: z.record(z.string(), z.unknown()).optional().describe(
    "JSON Schema to validate the resolved inputs context before execution. Fails the step if inputs don't match.",
  ),
  // JSON Schema for output validation (on top of executor's base schema)
  outputSchema: z.record(z.string(), z.unknown()).optional().describe(
    "JSON Schema to validate the executor's output (e.g. {taskId, taskOutput} for agent-task). " +
      "This is DIFFERENT from config.outputSchema which validates the agent's raw output.",
  ),
});

